//! Binary-level integration tests for `baton-get`.
//!
//! Spawns the compiled `baton-get` binary, pipes one Target per
//! NDJSON line into stdin, and asserts on the parsed output. Covers
//! the per-record decoration flags (`--avu` / `--acl` / `--size` /
//! `--checksum` / `--replicate` / `--timestamp`) wired in 8c, plus
//! the `--save` orthogonality and the skip-on-error guard.

use std::io::Write;
use std::process::{Command, Output, Stdio};

use baton_rs::types::{DataObject, Target};

const TEST_COLL: &str = "/testZone/home/irods";

fn baton_get_path() -> &'static str {
    env!("CARGO_BIN_EXE_baton-get")
}

fn run_baton_get(args: &[&str], input: &str) -> Output {
    let mut child = Command::new(baton_get_path())
        .args(args)
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .expect("spawn baton-get");
    {
        let stdin = child.stdin.as_mut().expect("stdin");
        stdin.write_all(input.as_bytes()).expect("write stdin");
    }
    drop(child.stdin.take());
    child.wait_with_output().expect("wait baton-get")
}

fn stdout_str(output: &Output) -> String {
    String::from_utf8(output.stdout.clone()).expect("utf8 stdout")
}

fn parse_targets(stdout: &str) -> Vec<Target> {
    stdout
        .lines()
        .filter(|l| !l.trim().is_empty())
        .map(|l| serde_json::from_str(l).expect("parse output target"))
        .collect()
}

fn iput(local: &str, remote: &str) {
    let status = Command::new("iput")
        .args(["-f", local, remote])
        .status()
        .expect("failed to spawn iput");
    assert!(status.success(), "iput {} {} failed", local, remote);
}

fn imeta_add_data_object(path: &str, attr: &str, value: &str) {
    let status = Command::new("imeta")
        .args(["add", "-d", path, attr, value])
        .status()
        .expect("failed to spawn imeta");
    assert!(status.success(), "imeta add -d {} failed", path);
}

struct IrodsCleanup(String);
impl Drop for IrodsCleanup {
    fn drop(&mut self) {
        let _ = Command::new("irm").args(["-r", "-f", &self.0]).status();
    }
}

struct LocalCleanup(std::path::PathBuf);
impl Drop for LocalCleanup {
    fn drop(&mut self) {
        let _ = std::fs::remove_file(&self.0);
    }
}

fn target_line(collection: &str, data_object: &str) -> String {
    let target = Target::DataObject(DataObject {
        collection: collection.to_string(),
        data_object: data_object.to_string(),
        size: None,
        checksum: None,
        data: None,
        directory: None,
        avus: None,
        access: None,
        replicates: None,
        timestamps: None,
        error: None,
    });
    let mut line = serde_json::to_string(&target).expect("serialise target");
    line.push('\n');
    line
}

fn unique_name(prefix: &str) -> String {
    format!("{}_{}", prefix, std::process::id())
}

fn data_object_unwrap(t: &Target) -> &DataObject {
    match t {
        Target::DataObject(d) => d,
        _ => panic!("expected DataObject target, got {:?}", t),
    }
}

#[test]
fn decoration_size_populates_size_in_inline_mode() {
    let local = "/tmp/baton_rs_bget_size_src";
    let payload: &[u8] = b"size_decoration_payload";
    std::fs::write(local, payload).expect("write");
    let name = unique_name("baton_rs_bget_size");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let output = run_baton_get(&["--size"], &target_line(TEST_COLL, &name));
    assert!(
        output.status.success(),
        "baton-get --size should succeed: stderr={}",
        String::from_utf8_lossy(&output.stderr),
    );
    let targets = parse_targets(&stdout_str(&output));
    assert_eq!(targets.len(), 1);
    let d = data_object_unwrap(&targets[0]);
    assert!(d.error.is_none(), "no error expected: {:?}", d.error);
    assert_eq!(
        d.size,
        Some(payload.len() as u64),
        "--size should populate size to the byte length",
    );
}

#[test]
fn decoration_avu_populates_avus_in_inline_mode() {
    let local = "/tmp/baton_rs_bget_avu_src";
    std::fs::write(local, b"avu_decoration_payload").expect("write");
    let name = unique_name("baton_rs_bget_avu");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote.clone());

    let attr = "baton_rs_bget_avu_attr";
    let value = format!("avu_decoration_value_{}", std::process::id());
    imeta_add_data_object(&remote, attr, &value);

    let output = run_baton_get(&["--avu"], &target_line(TEST_COLL, &name));
    assert!(output.status.success());
    let targets = parse_targets(&stdout_str(&output));
    let d = data_object_unwrap(&targets[0]);
    let avus = d.avus.as_ref().expect("--avu should populate avus");
    assert!(
        avus.iter().any(|a| a.attribute == attr && a.value == value),
        "staged AVU should appear in --avu output: {:?}",
        avus,
    );
}

#[test]
fn decoration_multiple_flags_populate_all_requested_fields() {
    let local = "/tmp/baton_rs_bget_multi_src";
    let payload: &[u8] = b"multi_decoration_payload";
    std::fs::write(local, payload).expect("write");
    let name = unique_name("baton_rs_bget_multi");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote.clone());

    imeta_add_data_object(&remote, "multi_attr", "multi_val");

    let output = run_baton_get(
        &["--size", "--checksum", "--avu", "--timestamp", "--replicate"],
        &target_line(TEST_COLL, &name),
    );
    assert!(output.status.success());
    let targets = parse_targets(&stdout_str(&output));
    let d = data_object_unwrap(&targets[0]);
    assert!(d.size.is_some(), "--size populated");
    assert!(d.avus.is_some(), "--avu populated");
    assert!(d.timestamps.is_some(), "--timestamp populated");
    assert!(d.replicates.is_some(), "--replicate populated");
    // checksum may be None if iput didn't compute one server-side;
    // the catalog field must exist on the result either way.
}

#[test]
fn decoration_works_alongside_save_mode() {
    let local = "/tmp/baton_rs_bget_save_src";
    let payload: &[u8] = b"save_with_decoration";
    std::fs::write(local, payload).expect("write");
    let name = unique_name("baton_rs_bget_save");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let local_dir = std::env::temp_dir();
    let local_path = local_dir.join(&name);
    let _local_cleanup = LocalCleanup(local_path.clone());

    // Inject the local `directory` field into the input target —
    // baton-get's --save mode requires it.
    let target = Target::DataObject(DataObject {
        collection: TEST_COLL.to_string(),
        data_object: name.clone(),
        size: None,
        checksum: None,
        data: None,
        directory: Some(local_dir.to_string_lossy().to_string()),
        avus: None,
        access: None,
        replicates: None,
        timestamps: None,
        error: None,
    });
    let mut line = serde_json::to_string(&target).expect("serialise");
    line.push('\n');

    let output = run_baton_get(&["--save", "--size"], &line);
    assert!(
        output.status.success(),
        "--save + --size should succeed: stderr={}",
        String::from_utf8_lossy(&output.stderr),
    );
    let targets = parse_targets(&stdout_str(&output));
    let d = data_object_unwrap(&targets[0]);
    assert_eq!(
        d.size,
        Some(payload.len() as u64),
        "decoration should populate size even in --save mode",
    );
    // Verify the bytes also landed on disk.
    let on_disk = std::fs::read(&local_path).expect("save target should exist on disk");
    assert_eq!(on_disk, payload, "save bytes should match the source");
}

#[test]
fn decoration_skips_when_get_already_errored() {
    // Reference a non-existent data object so get_one_annotated
    // produces an error annotation. With --size, the new
    // skip-on-error guard in decorate_result should not run a
    // stat call (which would itself fail and might mask the
    // original error). The original error annotation should be
    // present, and `size` should remain None.
    let missing = unique_name("baton_rs_bget_missing");
    let line = target_line(TEST_COLL, &missing);

    let output = run_baton_get(&["--size"], &line);
    let targets = parse_targets(&stdout_str(&output));
    assert_eq!(targets.len(), 1);
    let d = data_object_unwrap(&targets[0]);
    assert!(
        d.error.is_some(),
        "missing data object should annotate an error",
    );
    assert!(
        d.size.is_none(),
        "decoration should be skipped on errored target; size={:?}",
        d.size,
    );
}
